"use strict";(globalThis.webpackChunkcodaqui_institucional=globalThis.webpackChunkcodaqui_institucional||[]).push([[8413],{10492(a){a.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"2026/03/26/aumigo-prestacao-de-contas","metadata":{"permalink":"/comunidades/tisocial/blog/2026/03/26/aumigo-prestacao-de-contas","source":"@site/comunidades/tisocial/blog/2026-03-26-aumigo-prestacao-de-contas.mdx","title":"T.I. Social em a\xe7\xe3o \ud83d\udc3e\ud83c\udf6b \u2014 Presta\xe7\xe3o de contas da AUMIGO e da P\xe1scoa Solid\xe1ria","description":"\ud83c\udf89 Encerramos a primeira a\xe7\xe3o do ano da T.I. Social em apoio aos animais! A campanha AUMIGO reuniu conscientiza\xe7\xe3o, mobiliza\xe7\xe3o e muita solidariedade para ajudar protetores e projetos da nossa regi\xe3o.","date":"2026-03-26T00:00:00.000Z","tags":[{"inline":true,"label":"prestacao-de-contas","permalink":"/comunidades/tisocial/blog/tags/prestacao-de-contas"},{"inline":true,"label":"ti-social","permalink":"/comunidades/tisocial/blog/tags/ti-social"},{"inline":true,"label":"aumigo","permalink":"/comunidades/tisocial/blog/tags/aumigo"},{"inline":true,"label":"animais","permalink":"/comunidades/tisocial/blog/tags/animais"},{"inline":true,"label":"solidariedade","permalink":"/comunidades/tisocial/blog/tags/solidariedade"},{"inline":true,"label":"comunidade","permalink":"/comunidades/tisocial/blog/tags/comunidade"}],"readingTime":2.83,"hasTruncateMarker":true,"authors":[{"name":"Renan Ceratto","title":"Volunteer","url":"https://github.com/renanceratto","imageURL":"https://github.com/renanceratto.png","key":"renanceratto","page":null}],"frontMatter":{"slug":"2026/03/26/aumigo-prestacao-de-contas","title":"T.I. Social em a\xe7\xe3o \ud83d\udc3e\ud83c\udf6b \u2014 Presta\xe7\xe3o de contas da AUMIGO e da P\xe1scoa Solid\xe1ria","authors":["renanceratto"],"tags":["prestacao-de-contas","ti-social","aumigo","animais","solidariedade","comunidade"],"date":"2026-03-26T00:00:00.000Z"},"unlisted":false},"content":"\ud83c\udf89 **Encerramos a primeira a\xe7\xe3o do ano da T.I. Social em apoio aos animais!** A campanha **AUMIGO** reuniu conscientiza\xe7\xe3o, mobiliza\xe7\xe3o e muita solidariedade para ajudar protetores e projetos da nossa regi\xe3o.\\n\\n\x3c!-- truncate --\x3e\\n\\n## \ud83d\udc36 Sobre a campanha\\n\\nMais do que arrecadar recursos, a AUMIGO foi sobre **gente cuidando de gente \u2014 e de bichos**. Al\xe9m da cartilha com orienta\xe7\xf5es sobre como agir em situa\xe7\xf5es envolvendo animais, realizamos uma **campanha de doa\xe7\xe3o e venda de cookies**, que ajudou a garantir alimento para muitos pets resgatados. \ud83d\udc31\\n\\n> \ud83d\udc9a Cada cookie vendido, cada real doado e cada compartilhamento se transformou em ra\xe7\xe3o, medicamento e cuidado para quem mais precisa.\\n\\n---\\n\\nimport Grid from \'@mui/material/Grid\';\\nimport Card from \'@mui/material/Card\';\\nimport CardContent from \'@mui/material/CardContent\';\\nimport Typography from \'@mui/material/Typography\';\\nimport Stack from \'@mui/material/Stack\';\\nimport VolunteerActivismIcon from \'@mui/icons-material/VolunteerActivism\';\\nimport RestaurantIcon from \'@mui/icons-material/Restaurant\';\\nimport PetsIcon from \'@mui/icons-material/Pets\';\\nimport MedicationIcon from \'@mui/icons-material/Medication\';\\n\\n## \ud83d\udcca O impacto que conseguimos juntos\\n\\n<Grid container spacing={2} sx={{ my: 2 }}>\\n  <Grid size={{ xs: 12, sm: 6 }}>\\n    <Card sx={{ height: \'100%\', borderLeft: \'4px solid\', borderColor: \'success.main\' }}>\\n      <CardContent>\\n        <Stack direction=\\"row\\" spacing={1.5} alignItems=\\"center\\" mb={1}>\\n          <VolunteerActivismIcon sx={{ color: \'success.main\' }} />\\n          <Typography variant=\\"overline\\" color=\\"text.secondary\\">Arrecada\xe7\xe3o total</Typography>\\n        </Stack>\\n        <Typography variant=\\"h4\\" fontWeight={800} color=\\"success.main\\">R$ 2.859,45</Typography>\\n        <Typography variant=\\"body2\\" color=\\"text.secondary\\">Doa\xe7\xf5es + venda de cookies</Typography>\\n      </CardContent>\\n    </Card>\\n  </Grid>\\n  <Grid size={{ xs: 12, sm: 6 }}>\\n    <Card sx={{ height: \'100%\', borderLeft: \'4px solid\', borderColor: \'warning.main\' }}>\\n      <CardContent>\\n        <Stack direction=\\"row\\" spacing={1.5} alignItems=\\"center\\" mb={1}>\\n          <RestaurantIcon sx={{ color: \'warning.main\' }} />\\n          <Typography variant=\\"overline\\" color=\\"text.secondary\\">Ra\xe7\xe3o adquirida</Typography>\\n        </Stack>\\n        <Typography variant=\\"h4\\" fontWeight={800} color=\\"warning.main\\">417,5 kg</Typography>\\n        <Typography variant=\\"body2\\" color=\\"text.secondary\\">Distribu\xeddos entre protetores</Typography>\\n      </CardContent>\\n    </Card>\\n  </Grid>\\n  <Grid size={{ xs: 12, sm: 6 }}>\\n    <Card sx={{ height: \'100%\', borderLeft: \'4px solid\', borderColor: \'primary.main\' }}>\\n      <CardContent>\\n        <Stack direction=\\"row\\" spacing={1.5} alignItems=\\"center\\" mb={1}>\\n          <PetsIcon sx={{ color: \'primary.main\' }} />\\n          <Typography variant=\\"overline\\" color=\\"text.secondary\\">Animais beneficiados</Typography>\\n        </Stack>\\n        <Typography variant=\\"h4\\" fontWeight={800} color=\\"primary.main\\">+ de 350</Typography>\\n        <Typography variant=\\"body2\\" color=\\"text.secondary\\">C\xe3es e gatos resgatados</Typography>\\n      </CardContent>\\n    </Card>\\n  </Grid>\\n  <Grid size={{ xs: 12, sm: 6 }}>\\n    <Card sx={{ height: \'100%\', borderLeft: \'4px solid\', borderColor: \'secondary.main\' }}>\\n      <CardContent>\\n        <Stack direction=\\"row\\" spacing={1.5} alignItems=\\"center\\" mb={1}>\\n          <MedicationIcon sx={{ color: \'secondary.main\' }} />\\n          <Typography variant=\\"overline\\" color=\\"text.secondary\\">Itens adicionais</Typography>\\n        </Stack>\\n        <Typography variant=\\"h4\\" fontWeight={800} color=\\"secondary.main\\">Medicamentos</Typography>\\n        <Typography variant=\\"body2\\" color=\\"text.secondary\\">+ acess\xf3rios para os pets</Typography>\\n      </CardContent>\\n    </Card>\\n  </Grid>\\n</Grid>\\n\\n:::tip Transpar\xeancia\\nToda a arrecada\xe7\xe3o foi convertida em insumos para protetores e projetos parceiros \u2014 **nenhum centavo ficou pelo caminho**.\\n:::\\n\\n---\\n\\n## \ud83e\udd1d Para quem foram as doa\xe7\xf5es\\n\\nAs doa\xe7\xf5es foram destinadas a projetos e protetores da regi\xe3o que fazem um trabalho incr\xedvel pelos animais:\\n\\n- \ud83d\udc3e [@maurinha_dos_cachorrinhos](https://www.instagram.com/maurinha_dos_cachorrinhos/)\\n- \ud83d\udc3e [@amorsemracadefinida](https://www.instagram.com/amorsemracadefinida/)\\n- \ud83d\udc3e [@santuariofelinomga](https://www.instagram.com/santuariofelinomga/)\\n- \ud83d\udc3e [@projetoronronarmga](https://www.instagram.com/projetoronronarmga/)\\n\\n---\\n\\n## \ud83c\udf6b P\xe1scoa Solid\xe1ria \u2014 partilhar \xe9 o verdadeiro sabor\\n\\nUma P\xe1scoa **mais doce e cheia de prop\xf3sito**! \u2764\ufe0f\\n\\nNeste ano, o Projeto T.I. Social arrecadou:\\n\\n:::info P\xe1scoa Solid\xe1ria 2026\\n\ud83c\udf6b **464 caixas de bombons** entregues para a **APAE** e a **Associa\xe7\xe3o Oriental de Maring\xe1**, levando mais alegria para muitas crian\xe7as.\\n:::\\n\\nPorque partilhar \xe9 o verdadeiro sabor dessa data.\\n\\n---\\n\\n## \ud83d\udc9a Obrigado!\\n\\nObrigado a todos que contribu\xedram, compraram cookies, doaram ra\xe7\xe3o, compartilharam a campanha e ajudaram a fortalecer essa rede de cuidado pelos animais e pelas pessoas da nossa comunidade.\\n\\n\ud83c\udf10 Conhe\xe7a mais sobre o trabalho da comunidade no site oficial: **[tisocial.org.br](https://www.tisocial.org.br/)**"}]}}')}}]);